    make_q(15,"The response (dependent) variable goes on the:",["x-axis","*y-axis","Either axis","Neither axis"],"y-axis for the outcome variable."),
    make_q(16,"A scatter plot with a curved pattern suggests:",["Linear model","*A nonlinear relationship (quadratic, exponential, etc.)","No relationship","Perfect correlation"],"Curves indicate nonlinear models."),
    make_q(17,"Clustering in a scatter plot may indicate:",["Errors","*Subgroups in the data","Perfect correlation","No relationship"],"Clusters suggest distinct groups."),
