with open(PATH, "r", encoding="utf-8") as f:
    data = json.load(f)

count = 0
for key, extra_qs in EXTRA.items():
    if key in data:
        existing = data[key].get("quiz_questions", [])
        start_num = len(existing) + 1
        for i, q in enumerate(extra_qs):
            q["question_number"] = start_num + i
        data[key]["quiz_questions"] = existing + extra_qs
        count += 1

with open(PATH, "w", encoding="utf-8") as f:
    json.dump(data, f, indent=2, ensure_ascii=False)
print(f"✅ Algebra 1 U1-U4: expanded {count} lessons to 20 questions each")
